{
  "name": "Social Media Web App",
  "description": "A social media platform with a design inspired by Facebook, allowing users to view a feed of posts, stories, and interact with content."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';
import Header from './components/Header';
import LeftSidebar from './components/LeftSidebar';
import RightSidebar from './components/RightSidebar';
import Feed from './components/Feed';

const App: React.FC = () => {
  return (
    <div className="bg-gray-100 min-h-screen">
      <Header />
      <main className="flex justify-between pt-14">
        <LeftSidebar />
        <Feed />
        <RightSidebar />
      </main>
    </div>
  );
};

export default App;

export interface User {
  name: string;
  avatar: string;
}

export interface Story {
  id: number;
  user: User;
  storyImage: string;
}

export interface Post {
  id: number;
  user: User;
  timestamp: string;
  content: string;
  image?: string;
  likes: number;
  comments: number;
  shares: number;
}

import React from 'react';
import { currentUser } from '../constants';
import { UserIcon, UsersIcon, UserGroupIcon, BuildingStorefrontIcon, VideoCameraIcon, ClockIcon } from './icons/Icons';

const sidebarItems = [
  { icon: <UserIcon className="h-6 w-6 text-blue-500" />, label: currentUser.name },
  { icon: <UsersIcon className="h-6 w-6 text-blue-500" />, label: 'Friends' },
  { icon: <UserGroupIcon className="h-6 w-6 text-blue-500" />, label: 'Groups' },
  { icon: <BuildingStorefrontIcon className="h-6 w-6 text-blue-500" />, label: 'Marketplace' },
  { icon: <VideoCameraIcon className="h-6 w-6 text-blue-500" />, label: 'Watch' },
  { icon: <ClockIcon className="h-6 w-6 text-blue-500" />, label: 'Memories' },
];

const LeftSidebar: React.FC = () => {
  return (
    <aside className="hidden lg:block w-80 p-4 fixed top-14 left-0 h-full">
      <div className="space-y-2">
        {sidebarItems.map((item, index) => (
          <a
            key={index}
            href="#"
            className="flex items-center space-x-3 p-2 rounded-lg hover:bg-gray-200 transition-colors"
          >
            {item.label === currentUser.name ? (
               <img src={currentUser.avatar} alt={currentUser.name} className="w-7 h-7 rounded-full" />
            ) : (
              item.icon
            )}
            <span className="font-semibold text-gray-800">{item.label}</span>
          </a>
        ))}
      </div>
      <hr className="my-4" />
      <h2 className="text-gray-600 font-semibold mb-2">Your Shortcuts</h2>
      {/* Add shortcut items here */}
    </aside>
  );
};

export default LeftSidebar;

import React from 'react';
import Stories from './Stories';
import CreatePost from './CreatePost';
import Post from './Post';
import { posts } from '../constants';

const Feed: React.FC = () => {
  return (
    <div className="flex-grow max-w-2xl mx-auto px-2 sm:px-4 pt-6 pb-12">
      <div className="space-y-6">
        <Stories />
        <CreatePost />
        {posts.map((post) => (
          <Post key={post.id} post={post} />
        ))}
      </div>
    </div>
  );
};

export default Feed;

import React from 'react';
import { stories, currentUser } from '../constants';
import { PlusIcon } from './icons/Icons';

const Stories: React.FC = () => {
  return (
    <div className="flex space-x-2 overflow-x-auto pb-2 scrollbar-hide">
      {/* Create Story Card */}
      <div className="flex-shrink-0 w-28 h-48 rounded-xl shadow-md overflow-hidden relative cursor-pointer">
        <img src={currentUser.avatar} alt="Create Story" className="h-3/4 w-full object-cover"/>
        <div className="absolute bottom-0 left-0 right-0 h-1/4 bg-white flex flex-col items-center justify-end pb-2">
            <p className="text-xs font-semibold text-gray-700">Create story</p>
        </div>
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 transform -translate-y-full bg-blue-600 rounded-full border-4 border-white flex items-center justify-center h-10 w-10">
            <PlusIcon className="h-6 w-6 text-white"/>
        </div>
      </div>

      {stories.map((story) => (
        <div key={story.id} className="flex-shrink-0 w-28 h-48 rounded-xl shadow-md overflow-hidden relative group cursor-pointer">
          <img
            src={story.storyImage}
            alt={story.user.name}
            className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
          <img
            src={story.user.avatar}
            alt={story.user.name}
            className="absolute top-3 left-3 w-9 h-9 rounded-full border-4 border-blue-600"
          />
          <p className="absolute bottom-2 left-2 text-white font-semibold text-xs">
            {story.user.name}
          </p>
        </div>
      ))}
    </div>
  );
};

export default Stories;

import React from 'react';
import { currentUser } from '../constants';
import { VideoCameraIcon, PhotoIcon, FaceSmileIcon } from './icons/Icons';

const CreatePost: React.FC = () => {
  return (
    <div className="bg-white rounded-lg shadow-md p-4">
      <div className="flex items-center space-x-3 border-b pb-3 mb-3">
        <img src={currentUser.avatar} alt={currentUser.name} className="w-10 h-10 rounded-full" />
        <input
          type="text"
          placeholder={`What's on your mind, ${currentUser.name.split(' ')[0]}?`}
          className="flex-grow bg-gray-100 rounded-full py-2 px-4 focus:outline-none hover:bg-gray-200"
        />
      </div>
      <div className="flex justify-around">
        <button className="flex items-center space-x-2 text-gray-600 hover:bg-gray-100 py-2 px-4 rounded-lg w-1/3 justify-center">
          <VideoCameraIcon className="h-6 w-6 text-red-500" />
          <span className="font-semibold">Live video</span>
        </button>
        <button className="flex items-center space-x-2 text-gray-600 hover:bg-gray-100 py-2 px-4 rounded-lg w-1/3 justify-center">
          <PhotoIcon className="h-6 w-6 text-green-500" />
          <span className="font-semibold">Photo/video</span>
        </button>
        <button className="flex items-center space-x-2 text-gray-600 hover:bg-gray-100 py-2 px-4 rounded-lg w-1/3 justify-center">
          <FaceSmileIcon className="h-6 w-6 text-yellow-500" />
          <span className="font-semibold">Feeling/activity</span>
        </button>
      </div>
    </div>
  );
};

export default CreatePost;

import React, { useState } from 'react';
import { Post as PostType } from '../types';
import { EllipsisHorizontalIcon, GlobeAltIcon, HandThumbUpIcon, ChatBubbleOvalLeftIcon, ArrowUturnRightIcon } from './icons/Icons';

interface PostProps {
  post: PostType;
}

const Post: React.FC<PostProps> = ({ post }) => {
  const [liked, setLiked] = useState(false);

  return (
    <div className="bg-white rounded-lg shadow-md">
      {/* Post Header */}
      <div className="p-4 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <img src={post.user.avatar} alt={post.user.name} className="w-10 h-10 rounded-full" />
          <div>
            <p className="font-semibold text-gray-800">{post.user.name}</p>
            <div className="flex items-center space-x-1 text-xs text-gray-500">
              <span>{post.timestamp}</span>
              <span>·</span>
              <GlobeAltIcon className="h-3 w-3" />
            </div>
          </div>
        </div>
        <button className="text-gray-500 hover:bg-gray-100 rounded-full p-2">
          <EllipsisHorizontalIcon className="h-6 w-6" />
        </button>
      </div>

      {/* Post Content */}
      <p className="px-4 pb-2">{post.content}</p>
      {post.image && (
        <div className="bg-black">
            <img src={post.image} alt="Post content" className="w-full object-contain max-h-96" />
        </div>
      )}

      {/* Post Stats */}
      <div className="p-4 flex justify-between items-center text-sm text-gray-600">
        <div className="flex items-center space-x-1">
          <div className="bg-blue-600 rounded-full p-0.5">
            <HandThumbUpIcon className="h-3 w-3 text-white" />
          </div>
          <span>{post.likes + (liked ? 1 : 0)}</span>
        </div>
        <div className="flex space-x-4">
          <span>{post.comments} comments</span>
          <span>{post.shares} shares</span>
        </div>
      </div>

      {/* Post Actions */}
      <div className="border-t mx-4">
        <div className="flex justify-around py-1">
          <button 
            onClick={() => setLiked(!liked)}
            className={`flex items-center space-x-2 text-gray-600 hover:bg-gray-100 py-2 px-4 rounded-lg w-1/3 justify-center ${liked ? 'text-blue-600' : ''}`}
          >
            <HandThumbUpIcon className="h-6 w-6" />
            <span className="font-semibold">Like</span>
          </button>
          <button className="flex items-center space-x-2 text-gray-600 hover:bg-gray-100 py-2 px-4 rounded-lg w-1/3 justify-center">
            <ChatBubbleOvalLeftIcon className="h-6 w-6" />
            <span className="font-semibold">Comment</span>
          </button>
          <button className="flex items-center space-x-2 text-gray-600 hover:bg-gray-100 py-2 px-4 rounded-lg w-1/3 justify-center">
            <ArrowUturnRightIcon className="h-6 w-6" />
            <span className="font-semibold">Share</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Post;

